INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('PBS', 'Portable Batch System — traditional on-premises HPC job scheduler software', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Slurm', 'Simple Linux Utility for Resource Management — popular HPC cluster job scheduler', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('LSF', 'IBM Load Sharing Facility — enterprise batch workload scheduler used on-premises', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('SSM', 'AWS Systems Manager — manage EC2 instances remotely without SSH; run commands, patch, configure', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Athena', 'Amazon Athena — serverless SQL query service that reads data directly from S3, no database needed', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('IMDSv2', 'Instance Metadata Service v2 — more secure way to query EC2 metadata; requires a session token before fetching data', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('IMDS', 'Instance Metadata Service — endpoint at 169.254.169.254 that provides info about the running EC2 instance', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('STS', 'AWS Security Token Service — issues temporary credentials (access key + secret + session token)', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('CRR', 'Cross-Region Replication — automatically copies S3 objects to a bucket in another AWS region', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('IAM', 'Identity and Access Management — controls who (users, roles, services) can do what in AWS via policies', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('AMI', 'Amazon Machine Image — a snapshot template (OS + software) used to launch EC2 instances', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('EC2', 'Elastic Compute Cloud — virtual servers you rent in AWS; you choose the CPU, RAM, and OS', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('ALB', 'Application Load Balancer — Layer 7 load balancer; routes HTTP/HTTPS by path, host header, or query string', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('CloudFront', 'AWS Content Delivery Network — caches content at 400+ edge locations worldwide to reduce latency for users', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('CDN', 'Content Delivery Network — a network of edge servers that cache and serve content close to users to cut latency', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('RDS', 'Relational Database Service — managed SQL databases (MySQL, PostgreSQL, etc.) with automated backups and patching', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('SSO', 'Single Sign-On — log in once to access multiple AWS accounts or applications without re-entering credentials', 'services');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('EC2 fleet', 'A group of EC2 instances managed together, typically mixing On-Demand and Spot types', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Fleet', 'A group of EC2 instances managed together to meet a target capacity or cost, often mixing On-Demand and Spot', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Spot Instances', 'Spare EC2 capacity at up to 90% discount — AWS can reclaim them with a 2-minute interruption notice', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Reserved Instances', '1- or 3-year commitment to EC2 usage in exchange for up to 72% discount vs On-Demand pricing', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Savings Plans', 'Flexible commitment to a consistent usage amount ($/hr) for 1-3 years; applies across EC2, Lambda, Fargate', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Spot', 'EC2 Spot Instances — spare AWS capacity at up to 90% discount; can be interrupted with 2-min notice', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('On-Demand', 'EC2 On-Demand — pay per second/hour with no commitment; always available, never interrupted', 'compute');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('SSL/TLS', 'Protocols that encrypt data travelling over a network (in transit)', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('non-transitive', 'Routing only works directly — VPC Peering: if A peers B and B peers C, A still cannot reach C without its own peering', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('transitive', 'Routing through a middle point — if A connects to hub and B connects to hub, A can reach B indirectly', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Transit Gateway', 'Central hub that connects multiple VPCs and on-premises networks with transitive routing (A↔hub↔B)', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('VPC Peering', 'Direct private network link between two VPCs so they communicate as if on the same network; non-transitive', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('VPC Endpoint', 'Private connection from your VPC to AWS services (e.g. S3) without going through the public internet', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('VPC', 'Virtual Private Cloud — your own isolated network in AWS where you launch and control resources', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Internet Gateway', 'Allows resources in a public subnet to send and receive traffic to/from the internet', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('IGW', 'Internet Gateway — VPC component that allows public subnet resources to reach the internet', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('NAT Gateway', 'Network Address Translation Gateway — lets private subnet instances initiate outbound internet traffic without being publicly reachable', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('BGP', 'Border Gateway Protocol — dynamic routing protocol that exchanges routes between networks; used in Direct Connect and VPN', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('IPSec', 'Internet Protocol Security — encryption suite used to secure VPN tunnels over the public internet', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('CIDR', 'Classless Inter-Domain Routing — defines an IP address range. /16 = 65 536 IPs, /24 = 256 IPs', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('octet', 'Kumpulan 8 bits. IPv4 address ada 4 octets (4 × 8 = 32 bits). Nilai setiap octet = 0–255 kerana 2⁸ = 256 kemungkinan. Contoh: 192.168.100.10 → octet 1=192, octet 2=168, octet 3=100, octet 4=10', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('subnet', 'A subdivision of a VPC. Public subnet has a route to an Internet Gateway; private subnet has no direct internet access', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('inbound', 'Traffic flowing INTO your resource (e.g. an HTTP request arriving at your web server)', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('outbound', 'Traffic flowing OUT FROM your resource (e.g. your server connecting to a database)', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('deep packet inspection', 'Inspects the full content of network packets — not just headers — to detect malware, intrusions, or policy violations', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('intrusion prevention', 'Actively blocks detected attack patterns in network traffic in real-time before they reach the target', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('domain filtering', 'Allows or blocks traffic based on hostnames/domains (e.g. block *.malicious.com) rather than raw IP addresses', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('AES-256', 'Advanced Encryption Standard 256-bit — industry-standard symmetric encryption algorithm', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('SSL', 'Secure Sockets Layer — older protocol for encrypting data in transit (now replaced by TLS)', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('TLS', 'Transport Layer Security — modern encryption protocol for data in transit; successor to SSL', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('NACL', 'Network Access Control List — subnet-level firewall; stateless, evaluates every packet, supports both allow and deny rules', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('DDoS', 'Distributed Denial of Service — overwhelming a service with traffic from thousands of sources to make it unavailable', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('SQL injection', 'Attack where malicious SQL code is slipped into input fields to manipulate or dump a database', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('XSS', 'Cross-Site Scripting — attacker injects scripts into web pages to steal cookies or hijack user sessions', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('WAF', 'Web Application Firewall — filters HTTP/HTTPS requests at Layer 7 to block SQL injection, XSS, bots, and rate-limit abuse', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('DRT', 'DDoS Response Team — AWS experts available 24/7 to help Shield Advanced customers during active attacks', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Layer 7', 'Application layer in the OSI model — understands HTTP, HTTPS, DNS. WAF and ALB operate here', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Layer 3', 'Network layer in the OSI model — handles IP routing. Shield Standard protects here against volumetric floods', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Layer 4', 'Transport layer in the OSI model — handles TCP/UDP ports. Shield protects SYN floods and UDP reflection attacks', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('KMS', 'AWS Key Management Service — create, store, and manage encryption keys; used for data at rest encryption', 'encryption');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('SSE-KMS', 'Server-Side Encryption with KMS — objects/data are encrypted at rest automatically using keys in AWS KMS', 'encryption');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('CMK', 'Customer Managed Key — a KMS key you create and control (rotation, policies, auditing), vs AWS-managed keys', 'encryption');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('WORM', 'Write Once Read Many — data can be written exactly once and never modified or deleted after', 'encryption');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('envelope encryption', 'Data encrypted with a data key; the data key is encrypted by a KMS master key. Only the encrypted data key is stored alongside data', 'encryption');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Compliance mode', 'S3 Object Lock mode where NO user — not even root — can shorten or delete the retention period', 'encryption');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Governance mode', 'S3 Object Lock mode where users with special IAM permissions can override retention, unlike Compliance mode', 'encryption');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('legal hold', 'An S3 Object Lock flag that blocks deletion indefinitely with no fixed expiry — removed only when explicitly released', 'encryption');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('retention period', 'The fixed time window during which an S3 object cannot be deleted or overwritten (used with Object Lock)', 'encryption');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Multi-AZ', 'Multi-Availability Zone — synchronous standby replica in a different AZ; automatic failover for high availability', 'database');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Read Replica', 'Asynchronous read-only copy of a database — offloads read queries; can exist in a different region', 'database');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Availability Zone', 'Isolated data centre cluster within an AWS Region. Each Region has 3+ AZs for redundancy', 'database');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('RPO', 'Recovery Point Objective — maximum acceptable data loss in time. RPO = 1 hour means you can afford to lose 1 hour of data', 'database');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('RTO', 'Recovery Time Objective — maximum acceptable downtime. RTO = 4 hours means systems must be back up within 4 hours', 'database');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('EBS', 'Elastic Block Store — persistent block storage (like a virtual hard drive) attached to one EC2 instance', 'storage');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('EFS', 'Elastic File System — managed NFS file system that can be shared across multiple EC2 instances simultaneously', 'storage');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('IOPS', 'Input/Output Operations Per Second — measures storage throughput. Higher IOPS = faster reads/writes (important for databases)', 'storage');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('stateful', 'Remembers connection state — allowed return traffic is automatically permitted without an explicit rule (like Security Groups)', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('stateless', 'Does not track connections — every packet is evaluated independently against rules, both directions need rules (like NACLs)', 'architecture');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('bastion host', 'EC2 in a public subnet used as the only SSH/RDP entry point into private subnet instances — connect to bastion first, then hop to private instances', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('jump host', 'Another name for a bastion host — a hardened EC2 in a public subnet that you jump through to reach private subnet instances', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('Elastic IP', 'Static public IPv4 address allocated to your AWS account — stays fixed until released, survives instance stop/start; NAT Gateway requires one', 'networking');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('penetration testing', 'Authorised simulated attack to find vulnerabilities — AWS allows pentest on 8 services (EC2, RDS, CloudFront, Aurora, API GW, Lambda, Lightsail, Elastic Beanstalk) without prior approval', 'security');
INSERT OR IGNORE INTO glossary (term, definition, category) VALUES ('AUP', 'AWS Acceptable Use Policy — defines what is permitted and prohibited on AWS infrastructure, including security testing rules', 'security');